import React, { useState, useEffect } from 'react';

const defaultTicker = ["⭐ INDUS CUP 2K26! Win Cash Prizes up to ₹10,00,000! ⭐", "🚀 Hackathon 2025 by CSE Department - Register Now! 🚀"];

export default function Admin({ setIsAuth }) {
  const [activeTab, setActiveTab] = useState('events');
  const [events, setEvents] = useState([]);
  const [eventForm, setEventForm] = useState({ id: '', title: '', date: '', location: '', desc: '', category: 'Technical' });
  const [institutes, setInstitutes] = useState([]);
  const [instituteForm, setInstituteForm] = useState({ id: '', name: '', desc: '' });
  const [tickerItems, setTickerItems] = useState([]);
  const [newTicker, setNewTicker] = useState('');
  const [deleteModal, setDeleteModal] = useState({ show: false, type: '', id: '', name: '' });

  useEffect(() => {
    const loadData = () => {
      setEvents(JSON.parse(localStorage.getItem('indus_events') || '[]'));
      setInstitutes(JSON.parse(localStorage.getItem('indus_institutes') || '[]'));
      setTickerItems(JSON.parse(localStorage.getItem('indus_ticker') || JSON.stringify(defaultTicker)));
    };
    loadData();
    window.addEventListener('storage', loadData);
    return () => window.removeEventListener('storage', loadData);
  }, []);

  const saveEvents = (data) => { setEvents(data); localStorage.setItem('indus_events', JSON.stringify(data)); };
  const saveInstitutes = (data) => { setInstitutes(data); localStorage.setItem('indus_institutes', JSON.stringify(data)); };
  const saveTicker = (data) => { setTickerItems(data); localStorage.setItem('indus_ticker', JSON.stringify(data)); window.dispatchEvent(new Event('ticker-update')); };

  const handleEventSave = (e) => {
    e.preventDefault();
    const id = eventForm.id || Date.now().toString();
    const existing = events.findIndex(ev => ev.id === id);
    if (existing >= 0) {
      const updated = [...events];
      updated[existing] = { ...eventForm, id };
      saveEvents(updated);
    } else {
      saveEvents([...events, { ...eventForm, id }]);
    }
    setEventForm({ id: '', title: '', date: '', location: '', desc: '', category: 'Technical' });
  };

  const handleInstituteSave = (e) => {
    e.preventDefault();
    const id = instituteForm.id || Date.now().toString();
    const existing = institutes.findIndex(inst => inst.id === id);
    if (existing >= 0) {
      const updated = [...institutes];
      updated[existing] = { ...instituteForm, id };
      saveInstitutes(updated);
    } else {
      saveInstitutes([...institutes, { ...instituteForm, id }]);
    }
    setInstituteForm({ id: '', name: '', desc: '' });
  };

  const deleteItem = () => {
    const { type, id } = deleteModal;
    if (type === 'event') saveEvents(events.filter(e => e.id !== id));
    if (type === 'institute') saveInstitutes(institutes.filter(i => i.id !== id));
    setDeleteModal({ show: false, type: '', id: '', name: '' });
  };

  return (
    <div className="min-h-screen bg-[#f8f7f5] pb-24 px-8">
      {/* Top Console */}
      <div className="max-w-7xl mx-auto py-12 flex flex-col md:flex-row md:items-center justify-between border-b border-slate-200 mb-12">
        <div className="mb-6 md:mb-0">
           <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.4em] mb-2">Central Management Console</p>
           <h1 className="text-5xl font-black text-slate-900 tracking-tight leading-none">Indus Portal Admin</h1>
        </div>
        <div className="flex gap-4">
           <button onClick={() => window.location.href = '/'} className="px-8 py-4 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold hover:bg-slate-50 transition-all shadow-sm">Exit Admin</button>
           <button onClick={() => { setIsAuth(false); localStorage.removeItem('indus_admin_session'); window.location.href = '/'; }} className="px-8 py-4 bg-red-100 text-red-600 rounded-xl font-bold hover:bg-red-500 hover:text-white transition-all">Terminate Portal</button>
        </div>
      </div>

      <div className="max-w-7xl mx-auto grid grid-cols-12 gap-10 items-start">
        {/* Navigation Sidebar */}
        <div className="col-span-12 lg:col-span-3 lg:sticky lg:top-10 space-y-3 bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
           <span className="text-[10px] font-black uppercase text-slate-300 tracking-[0.2em] mb-4 px-4 block">System Units</span>
           {[
             { id: 'events', label: 'Global Events' },
             { id: 'institutes', label: 'Units Directory' },
             { id: 'ticker', label: 'Information Ticker' }
           ].map(tab => (
             <button 
               key={tab.id}
               onClick={() => setActiveTab(tab.id)}
               className={`w-full text-left px-6 py-5 rounded-2xl text-sm font-bold uppercase tracking-widest transition-all ${activeTab === tab.id ? 'bg-slate-900 text-white shadow-xl shadow-slate-900/10 scale-[1.03]' : 'text-slate-400 hover:text-slate-900 hover:bg-slate-50'}`}
             >
               {tab.label}
             </button>
           ))}
        </div>

        {/* Global Content Canvas */}
        <div className="col-span-12 lg:col-span-9 space-y-12">
           {activeTab === 'events' && (
             <div className="grid grid-cols-12 gap-8 items-start">
                <div className="col-span-12 xl:col-span-5">
                   <div className="bg-white border border-slate-200 p-10 rounded-3xl shadow-sm">
                      <h2 className="text-3xl font-black mb-8 text-slate-900 tracking-tight leading-none">{eventForm.id ? 'Refine Event' : 'New Global Event'}</h2>
                      <form onSubmit={handleEventSave} className="space-y-6">
                         {[
                           { label: 'Title', name: 'title', type: 'text', placeholder: 'Event Name...' },
                           { label: 'Date Reference', name: 'date', type: 'text', placeholder: 'e.g. 24th April 2026' },
                           { label: 'Venue/Location', name: 'location', type: 'text', placeholder: 'Auditorium A...' }
                         ].map(field => (
                           <div key={field.name} className="space-y-3">
                              <label className="text-[11px] font-black uppercase text-slate-400 tracking-widest pl-1">{field.label}</label>
                              <input required type={field.type} value={eventForm[field.name]} onChange={e => setEventForm({...eventForm, [field.name]: e.target.value})} className="w-full bg-slate-50 border border-slate-200 px-6 py-4 rounded-2xl outline-none font-bold text-lg focus:border-slate-900 focus:bg-white transition-all shadow-sm" placeholder={field.placeholder} />
                           </div>
                         ))}
                         <button type="submit" className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl hover:bg-black shadow-lg shadow-slate-900/10 transition-all uppercase tracking-widest text-xs">Authorize Event</button>
                      </form>
                   </div>
                </div>

                <div className="col-span-12 xl:col-span-7 bg-white/40 p-10 rounded-3xl border border-slate-200/50 shadow-inner">
                   <div className="flex flex-col gap-4 max-h-[70vh] overflow-y-auto pr-4 custom-scrollbar">
                      {events.map(ev => (
                        <div key={ev.id} className="bg-white p-8 rounded-3xl border border-slate-200 flex flex-col md:flex-row items-center justify-between hover:shadow-2xl transition-all duration-300 group gap-8 border-l-8 border-l-slate-900">
                           <div className="flex-1 shrink-0 px-2">
                              <div className="text-[10px] font-black text-slate-300 tracking-[0.2em] mb-2 uppercase">{ev.date} • {ev.location}</div>
                              <h4 className="text-2xl font-black text-slate-900 tracking-tighter leading-tight">{ev.title}</h4>
                           </div>
                           <div className="flex gap-4 shrink-0">
                              <button onClick={() => setEventForm(ev)} className="w-14 h-14 bg-slate-50 border border-slate-100 text-slate-400 rounded-2xl flex items-center justify-center hover:text-slate-900 hover:bg-slate-100 transition-all"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                              <button onClick={() => setDeleteModal({ show: true, type: 'event', id: ev.id, name: ev.title })} className="w-14 h-14 bg-white border border-red-50 text-red-100 rounded-2xl flex items-center justify-center hover:text-white hover:bg-red-500 hover:border-red-500 transition-all shadow-sm"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                           </div>
                        </div>
                      ))}
                   </div>
                </div>
             </div>
           )}

           {activeTab === 'institutes' && (
             <div className="grid grid-cols-12 gap-8 items-start">
                <div className="col-span-12 md:col-span-5">
                   <div className="bg-white border border-slate-200 p-10 rounded-3xl shadow-sm">
                      <h2 className="text-3xl font-black mb-8 text-slate-900 tracking-tight leading-none">{instituteForm.id ? 'Refine Unit' : 'New Institute'}</h2>
                      <form onSubmit={handleInstituteSave} className="space-y-6">
                         <div className="space-y-3">
                            <label className="text-[11px] font-black uppercase text-slate-400 tracking-widest pl-1">Unit Title</label>
                            <input required type="text" value={instituteForm.name} onChange={e => setInstituteForm({...instituteForm, name: e.target.value})} className="w-full bg-slate-50 border border-slate-200 px-6 py-4 rounded-2xl outline-none font-bold text-lg focus:border-slate-900 focus:bg-white transition-all shadow-sm" placeholder="e.g. IITE" />
                         </div>
                         <div className="space-y-3">
                            <label className="text-[11px] font-black uppercase text-slate-400 tracking-widest pl-1">Tagline/Mission</label>
                            <textarea required value={instituteForm.desc} onChange={e => setInstituteForm({...instituteForm, desc: e.target.value})} className="w-full bg-slate-50 border border-slate-200 px-6 py-4 rounded-2xl outline-none font-bold text-lg min-h-[160px] focus:border-slate-900 focus:bg-white transition-all leading-relaxed shadow-sm" placeholder="Mission statement..." />
                         </div>
                         <button type="submit" className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl hover:bg-black shadow-lg shadow-slate-900/10 transition-all uppercase tracking-widest text-xs">Register Unit</button>
                      </form>
                   </div>
                </div>
                <div className="col-span-12 md:col-span-7 bg-white/40 p-10 rounded-3xl border border-slate-200/50 shadow-inner">
                   <div className="flex flex-col gap-4 max-h-[70vh] overflow-y-auto pr-4 custom-scrollbar">
                      {institutes.map(inst => (
                        <div key={inst.id} className="bg-white p-8 rounded-3xl border border-slate-200 flex flex-col md:flex-row items-center justify-between hover:shadow-2xl transition-all duration-300 group gap-8 border-l-8 border-l-slate-900">
                           <div className="flex-1 px-2">
                              <h4 className="text-2xl font-black text-slate-900 tracking-tighter leading-tight mb-2 uppercase">{inst.name}</h4>
                              <p className="text-sm font-bold text-slate-400 leading-relaxed italic">{inst.desc}</p>
                           </div>
                           <div className="flex gap-4 shrink-0">
                              <button onClick={() => setInstituteForm(inst)} className="w-14 h-14 bg-slate-50 border border-slate-100 text-slate-400 rounded-2xl flex items-center justify-center hover:text-slate-900 hover:bg-slate-100 transition-all"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                              <button onClick={() => setDeleteModal({ show: true, type: 'institute', id: inst.id, name: inst.name })} className="w-14 h-14 bg-white border border-red-50 text-red-100 rounded-2xl flex items-center justify-center hover:text-white hover:bg-red-500 hover:border-red-500 transition-all shadow-sm"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>
                           </div>
                        </div>
                      ))}
                   </div>
                </div>
             </div>
           )}

           {activeTab === 'ticker' && (
             <div className="bg-white border border-slate-200 p-12 rounded-[2.5rem] shadow-sm">
                <h2 className="text-4xl font-black mb-12 text-slate-900 tracking-tight leading-none text-center">Announcement Control</h2>
                <div className="max-w-3xl mx-auto space-y-10">
                   <div className="flex gap-4">
                      <input type="text" value={newTicker} onChange={e => setNewTicker(e.target.value)} className="flex-1 bg-slate-50 border border-slate-100 px-8 py-5 rounded-2xl outline-none font-bold text-xl focus:border-slate-800 transition-all shadow-sm" placeholder="Broadcast message..." />
                      <button onClick={() => { if(newTicker.trim()) { saveTicker([...tickerItems, newTicker.trim()]); setNewTicker(''); } }} className="bg-slate-900 text-white font-black px-10 py-5 rounded-2xl hover:bg-black transition-all shadow-lg shadow-slate-900/10 uppercase tracking-widest text-xs">Post</button>
                   </div>
                   <div className="space-y-4">
                      {tickerItems.map((item, id) => (
                        <div key={id} className="bg-slate-50 p-6 rounded-2xl flex items-center justify-between group border border-slate-100 hover:bg-white hover:border-slate-200 transition-all shadow-sm">
                           <span className="font-bold text-slate-600 text-base flex-1 pr-10">{item}</span>
                           <button onClick={() => saveTicker(tickerItems.filter((_, i) => i !== id))} className="w-10 h-10 bg-white border border-red-50 text-red-200 rounded-xl flex items-center justify-center hover:bg-red-500 hover:text-white hover:border-red-500 transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg></button>
                        </div>
                      ))}
                   </div>
                </div>
             </div>
           )}
        </div>
      </div>

      {deleteModal.show && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-8">
           <div className="bg-white p-12 rounded-[2.5rem] max-w-lg w-full shadow-2xl border border-white text-center">
              <div className="w-24 h-24 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-10"><svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg></div>
              <h3 className="text-3xl font-black text-slate-900 tracking-tight leading-none mb-6 italic uppercase">Irreversible Action</h3>
              <p className="text-slate-400 font-bold mb-10 leading-relaxed px-8">Confirming this will permanently erase the record of <span className="text-slate-900 font-black text-lg underline">"{deleteModal.name}"</span>. Proceed with caution.</p>
              <div className="flex gap-4">
                 <button onClick={() => setDeleteModal({ show: false, type: '', id: '', name: '' })} className="flex-1 bg-slate-100 text-slate-500 font-black py-5 rounded-2xl hover:bg-slate-200 transition-all uppercase tracking-widest text-xs">Dismiss</button>
                 <button onClick={deleteItem} className="flex-1 bg-red-500 text-white font-black py-5 rounded-2xl hover:bg-red-600 shadow-xl shadow-red-200 transition-all uppercase tracking-widest text-xs">Authorize Deletion</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
}
